package nestedforlooptrainglepyramid;

public class trainglepyramid {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int row,col;
		for (row = 5; row<=5;row--)
		{
			for(col = 1 ; col<=row;col++)
			{
				System.out.print("*");

			}
			System.out.println("");
		}
		
}
}

